Hello there,
When you need to visualize connected systems — network topologies, infrastructure diagrams, dependency graphs — manually positioning nodes and routing edges becomes painful fast.
ELK (Eclipse Layout Kernel) solves this by automatically calculating optimal positions for nodes and routing edges between them. You give it a JSON graph, it gives you coordinates.
In this article, we’ll use ELK.js with D3 to build an interactive diagram renderer in JavaScript.
Press enter or click to view image in full size

I’m going to use it in JavaScript but we can use it any where like Angular or JavaScript or create a reusable npm package.
First include elk js and d3 using package json or CDN
Now lets see what is the JSON structure require for ELK.
# ELK.js JSON Structure## Root Object
```json
{
"id": "string", // Required: Unique identifier for the root graph
"layoutOptions": {}, // Optional: Layout configuration options
"children": [], // Required: Array of nodes/children
"edges": [] // Optional: Array of edges connecting nodes
}
```
## Layout Options
Common layout options that control the graph appearance:
```json
"layoutOptions": {
"elk.algorithm": "layered", // Algorithm: "layered", "force", "stress", etc.
"elk.direction": "DOWN", // Direction: "UP", "DOWN", "LEFT", "RIGHT"
"elk.spacing.nodeNode": "80", // Space between nodes (same layer)
"elk.layered.spacing.nodeNodeBetweenLayers": "100", // Space between layers
"elk.edgeRouting": "ORTHOGONAL" // Edge style: "ORTHOGONAL", "POLYLINE", "SPLINES"
}
```
## Children (Nodes)
Each node in the graph:
```json
{
"id": "string", // Required: Unique node identifier
"width": 120, // Required: Node width in pixels
"height": 80, // Required: Node height in pixels
"labels": [ // Optional: Array of text labels
{
"text": "Node Label"
}
],
"ports": [], // Optional: Array of connection points
"children": [] // Optional: Nested child nodes (hierarchical)
}
```
## Ports
Connection points on nodes:
```json
{
"id": "string", // Required: Unique port identifier
"width": 10, // Optional: Port width
"height": 10, // Optional: Port height
"properties": { // Optional: Port positioning
"port.side": "NORTH" // Side: "NORTH", "SOUTH", "EAST", "WEST"
},
"labels": [ // Optional: Port labels
{
"text": "P1"
}
]
}
```
## Edges
Connections between nodes or ports:
```json
{
"id": "string", // Required: Unique edge identifier
"sources": ["node_id"], // Required: Array of source node/port IDs
"targets": ["node_id"], // Required: Array of target node/port IDs
"labels": [ // Optional: Edge labels
{
"text": "Connection"
}
]
}
```
## Complete Example
```json
{
"id": "root",
"layoutOptions": {
"elk.algorithm": "layered",
"elk.direction": "RIGHT"
},
"children": [
{
"id": "n1",
"width": 100,
"height": 60,
"labels": [{ "text": "Node 1" }],
"ports": [
{
"id": "n1_p1",
"properties": { "port.side": "EAST" }
}
]
},
{
"id": "n2",
"width": 100,
"height": 60,
"labels": [{ "text": "Node 2" }],
"ports": [
{
"id": "n2_p1",
"properties": { "port.side": "WEST" }
}
]
}
],
"edges": [
{
"id": "e1",
"sources": ["n1_p1"],
"targets": ["n2_p1"]
}
]
}
```
## Key Points
- **id**: Must be unique across all nodes, ports, and edges
- **width/height**: Required for nodes to calculate layout
- **sources/targets**: Can reference node IDs directly or port IDs for precise connections
- **layoutOptions**: Extensive options available in ELK documentation
- **Hierarchical**: Nodes can contain children for nested layouts
Now lets look at the implementation file
// src/lib/elk.jsimport ELK from 'elkjs/lib/elk.bundled.js';
import * as d3 from 'd3';
export class ElkViz {
constructor(container, config = {}) {
this.container = d3.select(container);
this.config = {
width: config.width || 800,
height: config.height || 600,
...config
};
this.elk = new ELK();
this.eventHandlers = {};
this.svg = null;
}
on(event, handler) {
this.eventHandlers[event] = handler;
return this;
}
emit(event, data) {
if (this.eventHandlers[event]) {
this.eventHandlers[event](data);
}
}
async render(data) {
const layout = await this.elk.layout(data);
this.renderLayout(layout);
}
renderLayout(layout) {
this.container.selectAll('*').remove();
// Create main SVG container
this.svg = this.container
.append('svg')
.attr('width', this.config.width)
.attr('height', this.config.height);
// Create tooltip div
const tooltip = this.container
.append('div')
.style('position', 'absolute')
.style('visibility', 'hidden')
.style('background-color', 'rgba(0, 0, 0, 0.8)')
.style('color', '#fff')
.style('padding', '8px 12px')
.style('border-radius', '4px')
.style('font-size', '12px')
.style('pointer-events', 'none')
.style('z-index', '1000')
.style('max-width', '300px')
.style('word-wrap', 'break-word');
// Create group for zoom/pan transformations
const g = this.svg.append('g');
// Setup zoom behavior (mouse wheel zoom, drag to pan)
const zoom = d3.zoom()
.scaleExtent([0.1, 4])
.on('zoom', (event) => {
g.attr('transform', event.transform);
});
this.svg.call(zoom);
// Define arrow markers for edge endpoints
const defs = g.append('defs');
defs.append('marker')
.attr('id', 'elk-arrow')
.attr('markerWidth', 10)
.attr('markerHeight', 10)
.attr('refX', 8)
.attr('refY', 3)
.attr('orient', 'auto')
.append('polygon')
.attr('points', '0 0, 10 3, 0 6')
.attr('fill', '#999');
// Define animated dashed line style
const style = defs.append('style');
style.text(`
@keyframes dash {
to {
stroke-dashoffset: -20;
}
}
.animated-edge {
stroke-dasharray: 5, 5;
animation: dash 1s linear infinite;
}
`);
// Draw edges (connections between nodes)
if (layout.edges) {
g.append('g')
.selectAll('path')
.data(layout.edges)
.enter()
.append('path')
.attr('d', d => {
const points = d.sections[0].bendPoints || [];
const start = d.sections[0].startPoint;
const end = d.sections[0].endPoint;
return `M ${start.x} ${start.y} ${points.map(p => `L ${p.x} ${p.y}`).join(' ')} L ${end.x} ${end.y}`;
})
.attr('stroke', '#999')
.attr('stroke-width', 2)
.attr('fill', 'none')
.attr('marker-end', 'url(#elk-arrow)')
.attr('class', d => d.animated ? 'animated-edge' : '')
.style('cursor', 'pointer')
.on('click', (event, d) => {
event.stopPropagation();
this.emit('edgeClick', d);
})
.on('mouseover', (event, d) => {
event.stopPropagation();
d3.select(event.currentTarget).attr('stroke', '#4dabf7').attr('stroke-width', 3);
tooltip.style('visibility', 'visible')
.html(`<strong>Edge:</strong> ${d.id || 'Connection'}<br/>${d.sources?.[0] || ''} → ${d.targets?.[0] || ''}`);
this.emit('edgeHover', d);
})
.on('mousemove', (event) => {
tooltip.style('top', (event.pageY - 10) + 'px')
.style('left', (event.pageX + 10) + 'px');
})
.on('mouseout', (event, d) => {
d3.select(event.currentTarget).attr('stroke', '#999').attr('stroke-width', 2);
tooltip.style('visibility', 'hidden');
});
}
// Draw nodes (main rectangles representing equipment)
if (layout.children) {
const nodes = g.append('g')
.selectAll('g')
.data(layout.children)
.enter()
.append('g')
.attr('transform', d => `translate(${d.x},${d.y})`)
.style('cursor', 'pointer');
// Draw node rectangles (equipment boxes)
nodes.append('rect')
.attr('width', d => d.width)
.attr('height', d => d.height)
.attr('fill', '#69b3a2')
.attr('stroke', '#333')
.attr('stroke-width', 2)
.style('cursor', 'pointer')
.on('click', (event, d) => {
event.stopPropagation();
this.emit('nodeClick', d);
})
.on('mouseover', (event, d) => {
event.stopPropagation();
d3.select(event.currentTarget).attr('fill', '#51cf66');
const tooltipContent = d.tooltip ? d.tooltip.join('<br/>') :
(d.display ? d.display.join('<br/>') :
`<strong>Node:</strong> ${d.id}`);
tooltip.style('visibility', 'visible').html(tooltipContent);
this.emit('nodeHover', d);
})
.on('mousemove', (event) => {
tooltip.style('top', (event.pageY - 10) + 'px')
.style('left', (event.pageX + 10) + 'px');
})
.on('mouseout', (event, d) => {
d3.select(event.currentTarget).attr('fill', '#69b3a2');
tooltip.style('visibility', 'hidden');
});
// Draw node labels (equipment IDs/names)
nodes.append('text')
.attr('text-anchor', 'middle')
.attr('x', d => d.width / 2)
.attr('y', d => d.height / 2)
.attr('dy', '0.3em')
.attr('fill', '#fff')
.attr('font-size', '12px')
.style('pointer-events', 'none')
.text(d => d.labels?.[0]?.text || '');
// Draw ports (small rectangles on nodes representing connection points)
const self = this;
nodes.each(function(d) {
if (d.ports && d.ports.length > 0) {
const nodeGroup = d3.select(this);
d.ports.forEach(port => {
// Draw port rectangle with larger hit area
const portRect = nodeGroup.append('rect')
.attr('x', port.x)
.attr('y', port.y)
.attr('width', port.width)
.attr('height', port.height)
.attr('fill', '#ff6b6b')
.attr('stroke', '#c92a2a')
.attr('stroke-width', 1)
.style('cursor', 'pointer');
// Add invisible larger hit area for better interaction
const padding = 5;
nodeGroup.append('rect')
.attr('x', port.x - padding)
.attr('y', port.y - padding)
.attr('width', port.width + padding * 2)
.attr('height', port.height + padding * 2)
.attr('fill', 'transparent')
.style('cursor', 'pointer')
.on('click', function(event) {
event.stopPropagation();
portRect.attr('fill', '#ff8787');
self.emit('portClick', { node: d, port: port });
})
.on('mouseover', function(event) {
event.stopPropagation();
portRect.attr('fill', '#ff8787');
const tooltipContent = port.tooltip ||
`<strong>Port:</strong> ${port.id}<br/><strong>Manufacture:</strong> ${port.portManufacture || 'N/A'}`;
tooltip.style('visibility', 'visible').html(tooltipContent);
self.emit('portHover', { node: d, port: port });
})
.on('mousemove', function(event) {
tooltip.style('top', (event.pageY - 10) + 'px')
.style('left', (event.pageX + 10) + 'px');
})
.on('mouseout', function(event) {
portRect.attr('fill', '#ff6b6b');
tooltip.style('visibility', 'hidden');
});
// Draw port label (port number/name)
if (port.labels && port.labels[0]) {
nodeGroup.append('text')
.attr('x', port.x + port.width / 2)
.attr('y', port.y + port.height / 2)
.attr('text-anchor', 'middle')
.attr('dy', '0.3em')
.attr('fill', '#fff')
.attr('font-size', '8px')
.style('pointer-events', 'none')
.text(port.labels[0].text);
}
});
}
});
}
// Auto-fit: Calculate bounds and set initial zoom/pan to fit entire graph
const bounds = this.calculateBounds(layout);
const scale = Math.min(
this.config.width / bounds.width,
this.config.height / bounds.height
) * 0.9;
const translateX = (this.config.width - bounds.width * scale) / 2 - bounds.minX * scale;
const translateY = (this.config.height - bounds.height * scale) / 2 - bounds.minY * scale;
this.svg.call(zoom.transform, d3.zoomIdentity.translate(translateX, translateY).scale(scale));
}
calculateBounds(layout) {
if (!layout.children || layout.children.length === 0) {
return { minX: 0, minY: 0, width: 100, height: 100 };
}
let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
layout.children.forEach(node => {
minX = Math.min(minX, node.x);
minY = Math.min(minY, node.y);
maxX = Math.max(maxX, node.x + node.width);
maxY = Math.max(maxY, node.y + node.height);
});
return {
minX,
minY,
width: maxX - minX,
height: maxY - minY
};
}
}
This implementation file is appending elements using D3 JS to the diagram created by ELK , this can be modified as per the requirements.
